import { IPlugin } from '@shell/core/types';

export default function(plugin: any, context: any) {

  const { product, virtualType } = plugin['DSL'](context, 'cluster');

  product({
    ifHaveType: 'v1',
    inStore:    'cluster',
    icon:       'calendar'
  });

  virtualType({
    labelKey: 'planner.tasks.title',
    name:     'planner-tasks',
    route:    { name: 'c-cluster-planner-tasks' }
  });

  virtualType({
    labelKey: 'planner.alerts.title',
    name:     'planner-alerts',
    route:    { name: 'c-cluster-planner-alerts' }
  });

  virtualType({
    labelKey: 'planner.reports.title',
    name:     'planner-reports',
    route:    { name: 'c-cluster-planner-reports' }
  });

  plugin.register('nav', (navContext: any, { group }: any) => {
    group({
      name:     'planner',
      labelKey: 'planner.title',
      children: [
        'planner-tasks',
        'planner-alerts',
        'planner-reports'
      ],
      weight:   100
    });
  });
}